const PROM = 'http://monitoring-kube-prometheus-prometheus.monitoring.svc.cluster.local:9090/api/v1/query';

const q = async (query) => {
  const r = await $http.get({ url: PROM, qs: { query } });
  const res = r.data.data.result;
  return res.length > 0 ? parseFloat(res[0].value[1]) : 0;
};

const qAll = async (query) => {
  const r = await $http.get({ url: PROM, qs: { query } });
  return r.data.data.result;
};

// 오퍼레이터 업 상태
const upResult = await qAll('up{job=~"operator-spark.*"}');
const operatorUp = upResult.filter(r => r.value[1] === '1').length;
const operatorTotal = upResult.length;

// 애플리케이션 카운트
const totalApps    = await q('sum(spark_application_count) or vector(0)');
const runningApps  = await q('sum(spark_application_running_count) or vector(0)');
const failedApps   = await q('sum(spark_application_failure_count) or vector(0)');
const successApps  = await q('sum(spark_application_success_count) or vector(0)');
const submitCount  = await q('sum(spark_application_submit_count) or vector(0)');
const executorRun  = await q('sum(spark_executor_running_count) or vector(0)');

// 1시간 신규 실패 (increase)
const newFailures  = await q('sum(increase(spark_application_failure_count[1h])) or vector(0)');

const alerts = [];
if (operatorUp < operatorTotal) alerts.push(`🔴 오퍼레이터 Pod ${operatorTotal - operatorUp}개 다운`);
if (newFailures > 0)            alerts.push(`⚠️ 최근 1h 신규 실패: ${newFailures}건`);
if (failedApps > 0)             alerts.push(`📋 누적 실패 잡: ${failedApps}개`);
if (runningApps > 0)            alerts.push(`🔄 현재 실행 중: ${runningApps}개`);

const status = operatorUp < operatorTotal ? 'error'
             : newFailures > 0           ? 'warning'
             : 'ok';

return [{ json: {
  service: 'Spark Operator',
  status,
  metrics: { operatorUp, operatorTotal, totalApps, runningApps, failedApps, successApps, submitCount, executorRun, newFailures },
  alerts
}}];
